// Reset clip_status so dashboard shows real-time rebuild progress
const topicId2 = $input.first().json.topic_id || $input.first().json.data?.topic_id;
if (topicId2) {
  try {
    await fetch($env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId2 + '&clip_status=eq.complete', {
      method: 'PATCH',
      headers: {'apikey': $env.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
      body: JSON.stringify({clip_status: 'pending'})
    });
  } catch(e) { /* non-fatal */ }
}

const allScenes = $('Load All Scenes').all().map(item => item.json);
const topic = $('Load Topic').first().json;
const topicData = Array.isArray(topic) ? topic[0] : topic;
const topicId = topicData.id || $('Webhook Trigger').item.json.body.topic_id;
const topicTitle = (topicData.seo_title || 'video').replace(/[^a-zA-Z0-9_ -]/g, '').substring(0, 80);
const sanitizedTitle = topicTitle.replace(/[^a-zA-Z0-9_-]/g, '_');

function msToSrt(ms) {
  const totalSeconds = Math.floor(ms / 1000);
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  const millis = ms % 1000;
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')},${String(millis).padStart(3, '0')}`;
}

// Split text into chunks of ~10-12 words for readable captions
function splitIntoChunks(text, maxWords) {
  const words = text.trim().split(/\s+/);
  const chunks = [];
  for (let i = 0; i < words.length; i += maxWords) {
    chunks.push(words.slice(i, i + maxWords).join(' '));
  }
  return chunks;
}

let srtEntries = [];
let sequenceNum = 1;
let skippedCount = 0;
let totalDurationMs = 0;
const WORDS_PER_CHUNK = 10;

for (const scene of allScenes) {
  const startMs = scene.start_time_ms || 0;
  const endMs = scene.end_time_ms || (startMs + (scene.audio_duration_ms || 0));
  if (endMs > totalDurationMs) totalDurationMs = endMs;
  const sceneDuration = endMs - startMs;

  if (scene.skipped || !scene.narration_text || !scene.narration_text.trim()) {
    if (scene.skipped) skippedCount++;
    continue;
  }

  const text = scene.narration_text.trim();
  const chunks = splitIntoChunks(text, WORDS_PER_CHUNK);
  const totalWords = text.split(/\s+/).length;
  const msPerWord = sceneDuration / totalWords;

  let wordOffset = 0;
  for (const chunk of chunks) {
    const chunkWords = chunk.split(/\s+/).length;
    const chunkStartMs = Math.round(startMs + (wordOffset * msPerWord));
    const chunkEndMs = Math.round(startMs + ((wordOffset + chunkWords) * msPerWord));
    srtEntries.push(`${sequenceNum}\n${msToSrt(chunkStartMs)} --> ${msToSrt(chunkEndMs)}\n${chunk}\n`);
    sequenceNum++;
    wordOffset += chunkWords;
  }
}

const srtContent = srtEntries.join('\n');
const srtPath = `/tmp/production/${topicId}/captions/${sanitizedTitle}.srt`;
const srtContentB64 = Buffer.from(srtContent, 'utf8').toString('base64');

const sceneList = allScenes.map(s => ({
  id: s.id,
  scene_number: s.scene_number,
  scene_id: s.scene_id,
  visual_type: s.visual_type,
  audio_duration_ms: s.audio_duration_ms || 0,
  audio_file_url: s.audio_file_url,
  audio_file_drive_id: s.audio_file_drive_id,
  image_url: s.image_url,
  image_drive_id: s.image_drive_id,
  video_url: s.video_url,
  video_drive_id: s.video_drive_id,
  skipped: s.skipped || false,
  padded_num: String(s.scene_number).padStart(3, '0')
}));

return [{
  json: {
    topic_id: topicId,
    project_id: topicData.project_id || allScenes[0]?.project_id,
    topic_title: topicTitle,
    sanitized_title: sanitizedTitle,
    topic_number: topicData.topic_number,
    drive_folder_id: topicData.drive_folder_id,
    drive_subfolder_ids: topicData.drive_subfolder_ids,
    srt_content: srtContent,
    srt_content_b64: srtContentB64,
    srt_path: srtPath,
    srt_entry_count: sequenceNum - 1,
    scene_list: sceneList,
    total_scenes: sceneList.length,
    skipped_count: skippedCount,
    total_duration_ms: totalDurationMs,
    clips_built: 0,
    clips_failed: 0
  }
}];

// Write SRT file to disk
const { execSync } = require('child_process');
const data = $input.first().json;
const topicId = data.topic_id;
const srtPath = data.srt_path;
const srtContent = data.srt_content;

// Create all directories (no brace expansion - ash doesn't support it)
const baseDir = `/tmp/production/${topicId}`;
execSync(`mkdir -p ${baseDir}/captions ${baseDir}/clips ${baseDir}/final ${baseDir}/audio ${baseDir}/images ${baseDir}/video_clips`);

// Write SRT content via stdin to avoid ARG_MAX limits
execSync(`cat > '${srtPath}'`, { input: srtContent });

return [{ json: { ...data, srt_written: true } }];

// Convert scene_list to individual items for SplitInBatches
// FIXED: Reference Generate SRT directly (Write SRT File is now Execute Command)
const data = $('Generate SRT and Prepare').first().json;
const items = data.scene_list.map(scene => ({
  json: {
    ...scene,
    topic_id: data.topic_id,
    project_id: data.project_id,
    topic_title: data.topic_title,
    total_scenes: data.total_scenes
  }
}));
return items;

// Determine the FFmpeg command for this scene based on visual_type and skipped status
const scene = $input.first().json;
const topicId = scene.topic_id;
const padded = scene.padded_num;
const durationSec = (scene.audio_duration_ms / 1000).toFixed(3);

const audioPath = `/tmp/production/${topicId}/audio/scene_${padded}.mp3`;
const imagePath = `/tmp/production/${topicId}/images/scene_${padded}.png`;
const videoPath = `/tmp/production/${topicId}/video_clips/scene_${padded}.mp4`;
const outputPath = `/tmp/production/${topicId}/clips/scene_${padded}.mp4`;

let ffmpegCmd = '';
let needsDownload = { audio: false, image: false, video: false };

if (scene.skipped) {
  // Black frame with white '[Scene skipped]' text
  ffmpegCmd = `ffmpeg -y -f lavfi -i color=c=black:s=1920x1080:r=30:d=${durationSec} -i ${audioPath} -vf "drawtext=text='[Scene skipped]':fontcolor=white:fontsize=48:x=(w-text_w)/2:y=(h-text_h)/2" -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
} else if (scene.visual_type === 'static_image') {
  // Static image displayed for audio duration
  ffmpegCmd = `ffmpeg -y -loop 1 -i ${imagePath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
  needsDownload.image = true;
} else if (scene.visual_type === 'i2v' || scene.visual_type === 't2v') {
  // Video scene - loop if audio > 5s, trim if <= 5s
  // IMPORTANT: -map 0:v -map 1:a selects video from AI clip and audio from TTS
  // Without this, FFmpeg uses the AI clip's built-in audio instead of TTS voiceover
  if (scene.audio_duration_ms > 5000) {
    ffmpegCmd = `ffmpeg -y -stream_loop -1 -i ${videoPath} -i ${audioPath} -map 0:v -map 1:a -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  } else {
    ffmpegCmd = `ffmpeg -y -i ${videoPath} -i ${audioPath} -map 0:v -map 1:a -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  }
  needsDownload.audio = true;
  needsDownload.video = true;
} else {
  // Fallback: treat as static image
  ffmpegCmd = `ffmpeg -y -loop 1 -i ${imagePath} -i ${audioPath} -c:v libx264 -preset fast -crf 23 -pix_fmt yuv420p -c:a aac -b:a 128k -vf "scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2" -r 30 -t ${durationSec} -movflags +faststart ${outputPath}`;
  needsDownload.audio = true;
  needsDownload.image = true;
}

return [{
  json: {
    ...scene,
    ffmpeg_cmd: ffmpegCmd,
    output_path: outputPath,
    audio_path: audioPath,
    image_path: imagePath,
    video_path: videoPath,
    needs_download: needsDownload,
    duration_sec: parseFloat(durationSec)
  }
}];

// Download required assets - images/video via curl, audio handled separately by Google Drive node
const scene = $input.first().json;
const needs = scene.needs_download;
const topicId = scene.topic_id;
const padded = scene.padded_num;

// Helper: convert Google Drive view URL to direct download URL
function fixDriveUrl(url) {
  if (!url) return null;
  const match = url.match(/drive\.google\.com\/file\/d\/([^/]+)/);
  if (match) return `https://drive.google.com/uc?export=download&id=${match[1]}`;
  return url;
}

let downloadCmds = [];
let needsDriveAudioDownload = false;

// Audio: if it has a drive_id, the Google Drive HTTP Request node handles it
if (needs.audio) {
  if (scene.audio_file_drive_id) {
    needsDriveAudioDownload = true;
    // Don't add curl for audio — handled by Drive OAuth node
  } else if (scene.audio_file_url) {
    // Direct URL (not Drive)
    downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/audio/scene_${padded}.mp3 "${scene.audio_file_url}"`);
  }
}

if (needs.image) {
  const imageUrl = fixDriveUrl(scene.image_url) ||
    (scene.image_drive_id ? `https://drive.google.com/uc?export=download&id=${scene.image_drive_id}` : null);
  if (imageUrl) {
    downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/images/scene_${padded}.png "${imageUrl}"`);
  }
}

if (needs.video) {
  const videoUrl = fixDriveUrl(scene.video_url) ||
    (scene.video_drive_id ? `https://drive.google.com/uc?export=download&id=${scene.video_drive_id}` : null);
  if (videoUrl) {
    downloadCmds.push(`curl -sL -o /tmp/production/${topicId}/video_clips/scene_${padded}.mp4 "${videoUrl}"`);
  }
}

return [{
  json: {
    ...scene,
    needsDriveAudioDownload,
    download_cmd: downloadCmds.length > 0 ? downloadCmds.join(' && ') : 'echo "No curl downloads needed"'
  }
}];

// Download non-Drive assets (images/videos via curl)
const { execSync } = require('child_process');
const data = $input.first().json;
const cmd = data.download_cmd;

if (cmd && cmd !== 'echo "No curl downloads needed"') {
  try {
    execSync(cmd, { timeout: 300000 });
  } catch(e) {
    // Non-fatal: some assets might already exist or be unavailable
  }
}

return [{ json: { ...data, assets_downloaded: true } }];

// Build scene clip using FFmpeg shell command
// WITH post-build verification: checks output fps and sample_rate
const { execSync } = require('child_process');
const ffmpegCmd = $('Determine FFmpeg Command').item.json.ffmpeg_cmd;
const sceneData = $('Determine FFmpeg Command').item.json;
const outputPath = sceneData.output_path;

let stdout = '';
let success = false;
try {
  stdout = execSync(ffmpegCmd + ' 2>&1', { timeout: 120000 }).toString();
  success = true;
  stdout += '\nCLIP_SUCCESS';

  // POST-BUILD VERIFICATION: check that output matches expected specs
  try {
    var probeCmd = 'ffprobe -v quiet -select_streams v:0 -show_entries stream=r_frame_rate -of csv=p=0 "' + outputPath + '" 2>/dev/null';
    var fps = execSync(probeCmd, { shell: '/bin/sh', timeout: 5000 }).toString().trim();
    var srCmd = 'ffprobe -v quiet -select_streams a:0 -show_entries stream=sample_rate -of csv=p=0 "' + outputPath + '" 2>/dev/null';
    var sr = execSync(srCmd, { shell: '/bin/sh', timeout: 5000 }).toString().trim();
    if (fps !== '30/1' || sr !== '24000') {
      console.log('WARNING: scene_' + sceneData.padded_num + ' output mismatch (fps=' + fps + ' sr=' + sr + '). Re-encoding...');
      var fixedPath = outputPath.replace('.mp4', '_fixed.mp4');
      var fixCmd = 'ffmpeg -y -i "' + outputPath + '" -r 30 -c:v libx264 -preset fast -pix_fmt yuvj420p -c:a aac -ar 24000 -ac 1 -b:a 128k -movflags +faststart "' + fixedPath + '" 2>/dev/null && mv "' + fixedPath + '" "' + outputPath + '"';
      execSync(fixCmd, { shell: '/bin/sh', timeout: 120000 });
      stdout += '\nCLIP_REENCODED (was fps=' + fps + ' sr=' + sr + ')';
      console.log('  Fixed scene_' + sceneData.padded_num + ' to 30fps/24kHz');
    }
  } catch (probeErr) {
    console.log('WARNING: post-build probe failed for scene_' + sceneData.padded_num + ': ' + probeErr.message);
  }
} catch(e) {
  stdout = (e.stdout?.toString() || '') + '\n' + (e.stderr?.toString() || '') + '\nCLIP_FAILED';
}

return [{ json: { ...sceneData, stdout, success } }];

// Track clip completion/failure counts using workflow static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.clips_built) staticData.clips_built = 0;
if (!staticData.clips_failed) staticData.clips_failed = 0;
staticData.clips_built++;
return [{ json: { clips_built: staticData.clips_built, status: 'complete' } }];

// Track clip failure count
const staticData = $getWorkflowStaticData('global');
if (!staticData.clips_built) staticData.clips_built = 0;
if (!staticData.clips_failed) staticData.clips_failed = 0;
staticData.clips_failed++;
return [{ json: { clips_failed: staticData.clips_failed, status: 'failed', error: $('Build Scene Clip').item.json.stderr || 'FFmpeg error' } }];

// Generate concat list data — rewritten without require('fs')
// File existence checked via shell command in Concat Video node
const data = $('Generate SRT and Prepare').first().json;
const topicId = data.topic_id;
const totalScenes = data.total_scenes;
const sanitizedTitle = data.sanitized_title || data.topic_title.replace(/[^a-zA-Z0-9_-]/g, '_');
const concatPath = `/tmp/production/${topicId}/concat.txt`;

// Build shell command to generate concat.txt (checks file existence per clip)
const concatCmd = `for i in $(seq 1 ${totalScenes}); do p=$(printf "%03d" $i); f="/tmp/production/${topicId}/clips/scene_\${p}.mp4"; [ -f "$f" ] && echo "file '$f'"; done > ${concatPath}`;

return [{
  json: {
    topic_id: topicId,
    project_id: data.project_id,
    topic_title: data.topic_title,
    sanitized_title: sanitizedTitle,
    concat_path: concatPath,
    concat_cmd: concatCmd,
    clips_in_concat: totalScenes,
    total_scenes: totalScenes,
    skipped_count: data.skipped_count,
    srt_path: data.srt_path,
    drive_folder_id: data.drive_folder_id,
    drive_subfolder_ids: data.drive_subfolder_ids
  }
}];

// Concatenate all scene clips into final video
// WITH pre-concat validation: checks fps, sample_rate, codec on every clip
// Auto-re-encodes any mismatched clips before concat to prevent truncation
const { execSync } = require('child_process');
const item = $input.first().json;
const topicId = item.topic_id;
const baseDir = '/tmp/production/' + topicId;
const concatPath = baseDir + '/concat.txt';
const totalScenes = item.total_scenes || 170;

const TARGET_FPS = '30/1';
const TARGET_SR = '24000';
const TARGET_CODEC_V = 'h264';
const TARGET_CODEC_A = 'aac';

// =============================================
// STEP 1: Generate concat.txt
// =============================================
console.log('Generating concat.txt for ' + totalScenes + ' scenes...');
try {
  var lines = [];
  for (var i = 1; i <= totalScenes; i++) {
    var pad = String(i).padStart(3, '0');
    lines.push("file '" + baseDir + "/clips/scene_" + pad + ".mp4'");
  }
  var content = lines.join('\n');
  var b64 = Buffer.from(content).toString('base64');
  execSync('echo ' + b64 + ' | base64 -d > ' + concatPath, { shell: '/bin/sh', timeout: 10000 });
  var lineCount = execSync('wc -l < ' + concatPath, { shell: '/bin/sh' }).toString().trim();
  console.log('concat.txt generated with ' + lineCount + ' lines');
  if (parseInt(lineCount) === 0) {
    return [{ json: { ...item, stdout: 'CONCAT_FAILED: concat.txt is empty', assembly_mode: 'error' } }];
  }
} catch (e) {
  return [{ json: { ...item, stdout: 'CONCAT_FAILED: ' + e.message, assembly_mode: 'error' } }];
}

// =============================================
// STEP 2: PRE-CONCAT VALIDATION — check every clip
// =============================================
console.log('Validating clip specs (fps, sample_rate, codec)...');
var mismatched = [];
var expectedDurationSum = 0;
try {
  for (var i = 1; i <= totalScenes; i++) {
    var pad = String(i).padStart(3, '0');
    var clipPath = baseDir + '/clips/scene_' + pad + '.mp4';
    // Get fps, sample_rate, video codec, audio codec in one ffprobe call
    var probeCmd = 'ffprobe -v quiet -select_streams v:0 -show_entries stream=r_frame_rate,codec_name -of csv=p=0 "' + clipPath + '" 2>/dev/null && ffprobe -v quiet -select_streams a:0 -show_entries stream=sample_rate,codec_name -of csv=p=0 "' + clipPath + '" 2>/dev/null && ffprobe -v quiet -select_streams v:0 -show_entries stream=duration -of csv=p=0 "' + clipPath + '" 2>/dev/null';
    var probeOut = execSync(probeCmd, { shell: '/bin/sh', timeout: 10000 }).toString().trim().split('\n');
    // probeOut[0] = "h264,30/1", probeOut[1] = "aac,24000", probeOut[2] = duration
    var vInfo = (probeOut[0] || '').split(',');
    var aInfo = (probeOut[1] || '').split(',');
    var clipDur = parseFloat(probeOut[2] || '0');
    expectedDurationSum += clipDur;
    var vCodec = vInfo[0] || 'unknown';
    var fps = vInfo[1] || 'unknown';
    var aCodec = aInfo[0] || 'unknown';
    var sr = aInfo[1] || 'unknown';
    if (fps !== TARGET_FPS || sr !== TARGET_SR) {
      mismatched.push({ scene: i, pad: pad, fps: fps, sr: sr, vCodec: vCodec, aCodec: aCodec, path: clipPath });
    }
  }
  console.log('Validation complete. Expected total duration: ' + expectedDurationSum.toFixed(1) + 's');
} catch (e) {
  console.log('WARNING: Validation probe failed: ' + e.message + '. Continuing with concat...');
}

// =============================================
// STEP 3: AUTO-FIX mismatched clips
// =============================================
if (mismatched.length > 0) {
  console.log('Found ' + mismatched.length + ' mismatched clips. Re-encoding to 30fps/24kHz...');
  var fixFailed = 0;
  for (var m = 0; m < mismatched.length; m++) {
    var mc = mismatched[m];
    console.log('  Fixing scene_' + mc.pad + ' (fps=' + mc.fps + ' sr=' + mc.sr + ')');
    var fixedPath = mc.path.replace('.mp4', '_fixed.mp4');
    var fixCmd = 'ffmpeg -y -i "' + mc.path + '" -r 30 -c:v libx264 -preset fast -pix_fmt yuvj420p -c:a aac -ar 24000 -ac 1 -b:a 128k -movflags +faststart "' + fixedPath + '" 2>/dev/null && mv "' + fixedPath + '" "' + mc.path + '"';
    try {
      execSync(fixCmd, { shell: '/bin/sh', timeout: 120000 });
      console.log('  ✓ scene_' + mc.pad + ' fixed');
    } catch (e2) {
      console.log('  ✗ scene_' + mc.pad + ' fix FAILED: ' + e2.message);
      fixFailed++;
    }
  }
  if (fixFailed > 0) {
    console.log('WARNING: ' + fixFailed + ' clips could not be fixed. Concat may produce broken output.');
  } else {
    console.log('All ' + mismatched.length + ' mismatched clips fixed successfully.');
  }
} else {
  console.log('All ' + totalScenes + ' clips have matching specs. No re-encoding needed.');
}

// =============================================
// STEP 4: Run ffmpeg concat
// =============================================
var outputPath = baseDir + '/raw_final.mp4';
var ffcmd = 'ffmpeg -y -f concat -safe 0 -i ' + concatPath + ' -c:v copy -c:a aac -ar 48000 -ac 1 -b:a 128k -movflags +faststart ' + outputPath + ' 2>&1 && echo "CONCAT_SUCCESS" || echo "CONCAT_FAILED"';
console.log('Running ffmpeg concat...');
var stdout = '';
try {
  stdout = execSync(ffcmd, { shell: '/bin/sh', maxBuffer: 50 * 1024 * 1024, timeout: 1800000 }).toString().trim();
  console.log('Concat result: ' + stdout.slice(-200));
} catch (e) {
  stdout = 'CONCAT_FAILED: ' + e.message;
  return [{ json: { ...item, stdout: stdout, assembly_mode: 'concat' } }];
}

// =============================================
// STEP 5: POST-CONCAT DURATION VERIFICATION
// =============================================
if (stdout.indexOf('CONCAT_SUCCESS') !== -1 && expectedDurationSum > 0) {
  try {
    var vDur = parseFloat(execSync('ffprobe -v quiet -select_streams v:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
    var aDur = parseFloat(execSync('ffprobe -v quiet -select_streams a:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
    var vPct = (vDur / expectedDurationSum * 100).toFixed(1);
    var vaDiff = Math.abs(vDur - aDur).toFixed(1);
    console.log('POST-CONCAT CHECK: video=' + vDur.toFixed(1) + 's audio=' + aDur.toFixed(1) + 's expected=' + expectedDurationSum.toFixed(1) + 's (' + vPct + '%)');
    console.log('  Video/Audio drift: ' + vaDiff + 's');
    if (parseFloat(vPct) < 95) {
      stdout += '\nWARNING: Output is only ' + vPct + '% of expected duration. Video may be truncated!';
      console.log('  ⚠ DURATION MISMATCH — output is only ' + vPct + '% of expected. Possible truncation.');
    }
    if (parseFloat(vaDiff) > 5) {
      stdout += '\nWARNING: Video/Audio drift is ' + vaDiff + 's. Streams may be desynchronized!';
      console.log('  ⚠ V/A DRIFT — ' + vaDiff + 's difference between video and audio streams.');
    }
  } catch (e3) {
    console.log('POST-CONCAT CHECK: probe failed — ' + e3.message);
  }
}

return [{ json: { ...item, stdout: stdout, assembly_mode: 'concat', mismatched_clips_fixed: mismatched.length, expected_duration: expectedDurationSum } }];

const { execSync } = require('child_process');
const item = $input.first().json;
const topicId = item.topic_id;
const topicTitle = item.topic_title.replace(/[^a-zA-Z0-9_-]/g, '_');
const inputPath = '/tmp/production/' + topicId + '/raw_final.mp4';
const outputDir = '/tmp/production/' + topicId + '/final';
const outputPath = outputDir + '/' + topicTitle + '.mp4';

// Ensure final/ directory exists
try {
  execSync('mkdir -p "' + outputDir + '"', { shell: '/bin/sh', timeout: 5000 });
} catch(e) {}

// Audio-only normalize - caption burn happens OUTSIDE n8n (host-side service)
