  const startMs = scene.start_time_ms || 0;
  const endMs = scene.end_time_ms || (startMs + (scene.audio_duration_ms || 0));
  if (endMs > totalDurationMs) totalDurationMs = endMs;
  const sceneDuration = endMs - startMs;

  if (scene.skipped || !scene.narration_text || !scene.narration_text.trim()) {
    if (scene.skipped) skippedCount++;
    continue;
  }

  const text = scene.narration_text.trim();
  const chunks = splitIntoChunks(text, WORDS_PER_CHUNK);
  const totalWords = text.split(/\s+/).length;
  const msPerWord = sceneDuration / totalWords;

  let wordOffset = 0;
  for (const chunk of chunks) {
    const chunkWords = chunk.split(/\s+/).length;
    const chunkStartMs = Math.round(startMs + (wordOffset * msPerWord));
    const chunkEndMs = Math.round(startMs + ((wordOffset + chunkWords) * msPerWord));
    srtEntries.push(`${sequenceNum}\n${msToSrt(chunkStartMs)} --> ${msToSrt(chunkEndMs)}\n${chunk}\n`);
    sequenceNum++;
    wordOffset += chunkWords;
  }
}

