    var vCodec = vInfo[0] || 'unknown';
    var fps = vInfo[1] || 'unknown';
    var aCodec = aInfo[0] || 'unknown';
    var sr = aInfo[1] || 'unknown';
    if (fps !== TARGET_FPS || sr !== TARGET_SR) {
      mismatched.push({ scene: i, pad: pad, fps: fps, sr: sr, vCodec: vCodec, aCodec: aCodec, path: clipPath });
    }
  }
  console.log('Validation complete. Expected total duration: ' + expectedDurationSum.toFixed(1) + 's');
} catch (e) {
  console.log('WARNING: Validation probe failed: ' + e.message + '. Continuing with concat...');
}

// =============================================
// STEP 3: AUTO-FIX mismatched clips
// =============================================
if (mismatched.length > 0) {
  console.log('Found ' + mismatched.length + ' mismatched clips. Re-encoding to 30fps/24kHz...');
  var fixFailed = 0;
  for (var m = 0; m < mismatched.length; m++) {
    var mc = mismatched[m];
    console.log('  Fixing scene_' + mc.pad + ' (fps=' + mc.fps + ' sr=' + mc.sr + ')');
    var fixedPath = mc.path.replace('.mp4', '_fixed.mp4');
    var fixCmd = 'ffmpeg -y -i "' + mc.path + '" -r 30 -c:v libx264 -preset fast -pix_fmt yuvj420p -c:a aac -ar 24000 -ac 1 -b:a 128k -movflags +faststart "' + fixedPath + '" 2>/dev/null && mv "' + fixedPath + '" "' + mc.path + '"';
    try {
      execSync(fixCmd, { shell: '/bin/sh', timeout: 120000 });
      console.log('  ✓ scene_' + mc.pad + ' fixed');
    } catch (e2) {
      console.log('  ✗ scene_' + mc.pad + ' fix FAILED: ' + e2.message);
      fixFailed++;
    }
  }
  if (fixFailed > 0) {
    console.log('WARNING: ' + fixFailed + ' clips could not be fixed. Concat may produce broken output.');
  } else {
    console.log('All ' + mismatched.length + ' mismatched clips fixed successfully.');
  }
} else {
  console.log('All ' + totalScenes + ' clips have matching specs. No re-encoding needed.');
}

// =============================================
// STEP 4: Run ffmpeg concat
// =============================================
var outputPath = baseDir + '/raw_final.mp4';
var ffcmd = 'ffmpeg -y -f concat -safe 0 -i ' + concatPath + ' -c:v copy -c:a aac -ar 48000 -ac 1 -b:a 128k -movflags +faststart ' + outputPath + ' 2>&1 && echo "CONCAT_SUCCESS" || echo "CONCAT_FAILED"';
console.log('Running ffmpeg concat...');
var stdout = '';
try {
  stdout = execSync(ffcmd, { shell: '/bin/sh', maxBuffer: 50 * 1024 * 1024, timeout: 1800000 }).toString().trim();
  console.log('Concat result: ' + stdout.slice(-200));
} catch (e) {
  stdout = 'CONCAT_FAILED: ' + e.message;
  return [{ json: { ...item, stdout: stdout, assembly_mode: 'concat' } }];
}

// =============================================
// STEP 5: POST-CONCAT DURATION VERIFICATION
// =============================================
if (stdout.indexOf('CONCAT_SUCCESS') !== -1 && expectedDurationSum > 0) {
  try {
    var vDur = parseFloat(execSync('ffprobe -v quiet -select_streams v:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
    var aDur = parseFloat(execSync('ffprobe -v quiet -select_streams a:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
    var vPct = (vDur / expectedDurationSum * 100).toFixed(1);
    var vaDiff = Math.abs(vDur - aDur).toFixed(1);
    console.log('POST-CONCAT CHECK: video=' + vDur.toFixed(1) + 's audio=' + aDur.toFixed(1) + 's expected=' + expectedDurationSum.toFixed(1) + 's (' + vPct + '%)');
    console.log('  Video/Audio drift: ' + vaDiff + 's');
    if (parseFloat(vPct) < 95) {
      stdout += '\nWARNING: Output is only ' + vPct + '% of expected duration. Video may be truncated!';
      console.log('  ⚠ DURATION MISMATCH — output is only ' + vPct + '% of expected. Possible truncation.');
    }
    if (parseFloat(vaDiff) > 5) {
      stdout += '\nWARNING: Video/Audio drift is ' + vaDiff + 's. Streams may be desynchronized!';
      console.log('  ⚠ V/A DRIFT — ' + vaDiff + 's difference between video and audio streams.');
    }
  } catch (e3) {
    console.log('POST-CONCAT CHECK: probe failed — ' + e3.message);
  }
}

return [{ json: { ...item, stdout: stdout, assembly_mode: 'concat', mismatched_clips_fixed: mismatched.length, expected_duration: expectedDurationSum } }];

const { execSync } = require('child_process');
const item = $input.first().json;
const topicId = item.topic_id;
const topicTitle = item.topic_title.replace(/[^a-zA-Z0-9_-]/g, '_');
const inputPath = '/tmp/production/' + topicId + '/raw_final.mp4';
