// Ensure final/ directory exists
try {
  execSync('mkdir -p "' + outputDir + '"', { shell: '/bin/sh', timeout: 5000 });
} catch(e) {}

// Audio-only normalize - caption burn happens OUTSIDE n8n (host-side service)
const cmd = 'ffmpeg -y -i "' + inputPath + '" -af "loudnorm=I=-16:TP=-1.5:LRA=11" -c:v copy -c:a aac -ar 48000 -ac 1 -b:a 128k -movflags +faststart "' + outputPath + '" 2>&1 && echo "NORMALIZE_SUCCESS" || echo "NORMALIZE_FAILED"';

console.log('Audio-only normalize (captions burn via host service post-upload)...');

let stdout = '';
try {
  stdout = execSync(cmd, { shell: '/bin/sh', maxBuffer: 50 * 1024 * 1024, timeout: 600000 }).toString().trim();
  console.log('Result:', stdout.slice(-100));

  // POST-NORMALIZE VERIFICATION
  if (stdout.indexOf('NORMALIZE_SUCCESS') !== -1) {
    try {
      var vDur = parseFloat(execSync('ffprobe -v quiet -select_streams v:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
      var aDur = parseFloat(execSync('ffprobe -v quiet -select_streams a:0 -show_entries stream=duration -of csv=p=0 "' + outputPath + '" 2>/dev/null', { shell: '/bin/sh', timeout: 10000 }).toString().trim());
      var drift = Math.abs(vDur - aDur);
      console.log('POST-NORMALIZE: video=' + vDur.toFixed(1) + 's audio=' + aDur.toFixed(1) + 's drift=' + drift.toFixed(1) + 's');
      if (drift > 10) {
        stdout += '\nWARNING: V/A drift is ' + drift.toFixed(1) + 's after normalize!';
      }
    } catch(e2) {
      console.log('POST-NORMALIZE probe failed: ' + e2.message);
