return [{ json: { ...item, stdout, output_path: outputPath } }];

// Clean up temporary production files
const { execSync } = require('child_process');
const data = $('Generate Concat List').first().json;

try {
  execSync(`rm -rf "/tmp/production/${data.topic_id}/" 2>/dev/null`);
} catch(e) {
  // Ignore cleanup errors
}

return [{ json: { ...data, cleanup_done: true } }];

// Save Google Drive audio binary to disk
// Binary stored as filesystem-v2 ref — locate and copy via execSync (child_process works in INSECURE_MODE)
const { execSync } = require('child_process');
const scene = $('Prepare Downloads').first().json;
const topicId = scene.topic_id;
const padded = scene.padded_num;
const audioPath = `/tmp/production/${topicId}/audio/scene_${padded}.mp3`;

const items = $input.all();
const binaryField = Object.keys(items[0].binary || {})[0];

if (!binaryField) {
  return [{ json: { ...scene, audio_downloaded: false, error: 'no_binary_field' } }];
}

const meta = items[0].binary[binaryField];
let saved = false;

// Approach 1: filesystem-v2 binary ID → locate file on disk → cp
const binaryId = meta.id || '';
const relPath = binaryId.replace(/^filesystem-v2:/, '');

if (relPath) {
  // Try known n8n binary data directories
  const bases = [
    '/home/node/.n8n/binaryData/',
    '/home/node/.n8n/',
    '/data/binaryData/',
    '/data/',
    ''
  ];
  for (const base of bases) {
    try {
      const src = base + relPath;
      execSync(`test -f '${src}' && cp '${src}' '${audioPath}'`, { timeout: 5000 });
      saved = true;
      break;
    } catch(e) { /* try next */ }
  }

  // Fallback: find by UUID (last segment of path)
  if (!saved) {
    const uuid = relPath.split('/').pop();
    if (uuid && uuid.length > 8) {
      try {
        const found = execSync(
          `find /home/node/.n8n /data -maxdepth 6 -name '${uuid}' -type f 2>/dev/null | head -1`,
          { encoding: 'utf8', timeout: 15000 }
        ).trim();
        if (found) {
          execSync(`cp '${found}' '${audioPath}'`);
          saved = true;
        }
      } catch(e) {}
    }
  }
}

// Approach 2: .data might have base64 content (non-filesystem-v2 mode)
if (!saved && meta.data && typeof meta.data === 'string' && meta.data.length > 200) {
  try {
    execSync(`base64 -d > '${audioPath}'`, {
      input: meta.data,
      maxBuffer: 50 * 1024 * 1024
    });
    saved = true;
  } catch(e) {}
}

// Approach 3: Try require('fs') to read and list directory for diagnostics
if (!saved) {
  let diagInfo = 'id=' + binaryId;
  try {
    const fsMod = require('fs');
    diagInfo += ', fs=available';
    // List what's in the n8n data dir
    const n8nDir = '/home/node/.n8n';
    if (fsMod.existsSync(n8nDir)) {
      diagInfo += ', n8nDir=' + fsMod.readdirSync(n8nDir).join('|');
      const bdDir = n8nDir + '/binaryData';
      if (fsMod.existsSync(bdDir)) {
        diagInfo += ', binaryData=' + fsMod.readdirSync(bdDir).slice(0, 5).join('|');
      }
    }
  } catch(e) {
    diagInfo += ', fs=unavailable(' + e.message.substring(0, 50) + ')';
  }
  diagInfo += ', dataType=' + typeof meta.data;
  diagInfo += ', dataLen=' + (meta.data ? String(meta.data).length : 0);
  diagInfo += ', keys=' + Object.keys(meta).join(',');
  throw new Error('Cannot save audio. ' + diagInfo);
}

return [{ json: { ...scene, audio_downloaded: true } }];
